zustand["Ein schwarz angelaufener Talisman"] = 4 zustand["Ein dunkel angelaufener Talisman"] = 12 zustand["Ein angelaufener Talisman"] = 20 zustand["Ein stumpf aussehender Talisman"] = 28 zustand["Ein matter Talisman"] = 36 zustand["Ein matt schimmernder Talisman"] = 44 zustand["Ein schimmernder Talisman"] = 52 zustand["Ein polierter Talisman"] = 60 zustand["Ein hell polierter Talisman"] = 68 zustand["Ein glaenzender Talisman"] = 76 zustand["Ein hell glaenzender Talisman"] = 84 zustand["Ein funkelnder Talisman"] = 92 zustand["Ein strahlender Talisman"] = 100
local ausgabe = zustand[matches[1]]
if ausgabe then ausgabe = " (" .. ausgabe .. "%)" else ausgabe = " (???%)" end
selectCurrentLine() fg(farben.vg.info) bg(farben.hg.info)
if moveCursor(string.find(line, matches[1])+#(matches[1])-1, getLineNumber()) then insertText(ausgabe) end resetFormat()

