------------------------------------------------- -- Put your Lua functions here. -- -- -- -- Note that you can also use external Scripts -- -------------------------------------------------
ME = ME or {name="ABCDEFGHKLM", stufe=-1, gildenlevel=-1, gift=-1, para=0, plakette=0, vorsicht=-1, lp_alt=-1, lp=-1, lp_max=-1, kp=-1, kp_max=-1, str=99, dex=99, con=99, int=99, raum_kurz="No room", raum_region="~", raum_id="XXX"}
GUI = GUI or {angezeigt=false, lp_anzeige_blinkt=false, x=50, y=-150, width=510, height=150}

-------------------------------------------------
--         Put your Lua functions here.        --
--                                             --
-- Note that you can also use external Scripts --
-------------------------------------------------

function GUI:warning(text)
	echo("\n\n\n")
	decho("<255,255,0:0,0,0>WARNUNG (GUI): ")
	echo(text)
	echo("\n\n\n")
end

function GUI:error(text)
	echo("\n\n\n")
	decho("<255,155,0:0,0,0>FEHLER (GUI): ")
	echo(text)
	echo("\n\n\n")
end

function GUI:info(text)
	echo("\n\n\n")
	decho("<120,170,255:0,0,0>INFO (GUI): ")
	echo(text)
	echo("\n\n\n")
end
